// --- types.d.ts ---
export interface WeatherForecast {
  day: string;
  icon: string;
  high: number;
  low: number;
}

export interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: string;
  forecast: WeatherForecast[];
}

export interface HookReturn {
  formattedTemperature: string;
  formattedHumidity: string;
  formattedWind: string;
}

export interface WeatherMetricProps {
  label: string;
  value: string;
  icon: string;
}

export interface ForecastItemProps {
  data: WeatherForecast;
  unit: string;
}

// --- constants.ts ---
// constants.ts — static data, mappings, configurations
// No React, no design system imports. Pure data only.

export const WEATHER_ICONS: Record<string, string> = {
  Sunny: '☀️',
  Cloudy: '☁️',
  Rainy: '🌧️',
  Stormy: '⛈️',
  Snowy: '❄️',
  PartlyCloudy: '⛅',
};

export const UNITS = {
  metric: {
    temp: '°C',
    humidity: '%',
    wind: 'm/s',
  },
  imperial: {
    temp: '°F',
    humidity: '%',
    wind: 'mph',
  },
};

export const FORECAST_CONFIG = {
  maxDays: 5,
};

// --- hooks.ts ---
// hooks.ts — state, handlers, data transformations
import { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import type { Props, HookReturn } from './types';
import * as constants from './constants';

export function useComponent(props: Props): HookReturn {
  const { city, temperature, condition, humidity, windSpeed, unit, forecast } = props;

  return useMemo(() => {
    const u = unit || 'C';
    const windUnit = u === '°F' ? ' mph' : ' km/h';

    return {
      formattedTemperature: `${temperature}°${u}`,
      formattedHumidity: `${humidity}%`,
      formattedWind: `${windSpeed}${windUnit}`,
    };
  }, [temperature, humidity, windSpeed, unit]);
}


