// components/WeatherMetric.tsx
import React from 'react';
import { Stack, Text, Icon } from '@ggui-ai/design/primitives';
import { WeatherMetricProps } from '../types';

export const WeatherMetric = ({ label, value, icon }: WeatherMetricProps) => {
  return (
    <Stack 
      direction="horizontal" 
      gap="var(--ggui-spacing-2, 8px)" 
      align="center" 
      style={{ 
        backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)', 
        padding: 'var(--ggui-spacing-2, 8px)', 
        borderRadius: 'var(--ggui-shape-radius-md, 8px)' 
      }}
    >
      <Icon name={icon} size={20} />
      <Stack gap={0}>
        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{label}</Text>
        <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">{value}</Text>
      </Stack>
    </Stack>
  );
};

// --- components/ForecastItem.tsx ---
import React from 'react';
import { Box, Stack, Text, Icon } from '@ggui-ai/design/primitives';
import { ForecastItemProps } from '../types';

export const ForecastItem: React.FC<ForecastItemProps> = ({ data, unit }) => {
  return (
    <Box padding="var(--ggui-spacing-2)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-md)">
      <Stack align="center" gap="var(--ggui-spacing-2)">
        <Text variant="label">{data.day}</Text>
        <Icon name={data.icon} size={24} />
        <Text variant="bodySmall" color="var(--ggui-color-onSurface)">
          {data.high}{unit} / <Text as="span" color="var(--ggui-color-onSurfaceVariant)">{data.low}{unit}</Text>
        </Text>
      </Stack>
    </Box>
  );
};

// --- ui.tsx ---
// ui.tsx
import React from 'react';
import { Card, Stack, Box, Row, Divider, Heading, Text, Icon } from '@ggui-ai/design/primitives';
import { Props, WeatherForecast } from './types';

const WeatherMetric: React.FC<{ label: string; value: string; icon: string }> = ({ label, value, icon }) => (
  <Stack gap={1} align="center">
    <Icon name={icon} size={20} color="var(--ggui-color-onSurfaceVariant)" />
    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">{label}</Text>
    <Heading level={6}>{value}</Heading>
  </Stack>
);

const ForecastItem: React.FC<{ data: WeatherForecast; unit: string }> = ({ data, unit }) => (
  <Stack align="center" gap={2}>
    <Text variant="caption">{data.day}</Text>
    <Icon name={data.icon} size={24} />
    <Text variant="bodySmall" weight="semibold">
      {data.high}{unit} / {data.low}{unit}
    </Text>
  </Stack>
);

export const WeatherCard: React.FC<Props> = ({ city, temperature, condition, humidity, windSpeed, unit = '°C', forecast }) => {
  return (
    <Card padding={24} radius="lg" shadow="md">
      <Stack gap={24}>
        {/* Header */}
        <Stack gap={4} align="center">
          <Heading level={2}>{city}</Heading>
          <Heading level={1}>{temperature}{unit}</Heading>
          <Row align="center" gap={8}>
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">{condition}</Text>
            <Icon name="sun" size={16} color="var(--ggui-color-onSurfaceVariant)" />
          </Row>
        </Stack>

        {/* Metrics */}
        <Row justify="evenly">
          <WeatherMetric label="Humidity" value={`${humidity}%`} icon="droplet" />
          <WeatherMetric label="Wind" value={`${windSpeed} km/h`} icon="wind" />
        </Row>

        {/* Forecast */}
        <Divider margin={0} />
        <Row justify="between" align="center" style={{ overflowX: 'auto' }}>
          {forecast.map((item, index) => (
            <Box key={index} paddingX={8}>
              <ForecastItem data={item} unit={unit} />
            </Box>
          ))}
        </Row>
      </Stack>
    </Card>
  );
};

export default WeatherCard;

// --- entrypoint.tsx ---
// entrypoint.tsx — wires hooks + component, export default
import React from 'react';
import type { Props } from './types';
import { useComponent } from './hooks';
import { Component } from './components/index';

export default function Entrypoint(props: Props) {
  const state = useComponent(props);
  return <Component {...props} {...state} />;
}
